<?php declare(strict_types=1); namespace App\Http\Controllers\Attendance; use App\Http\Controllers\Controller; use App\Http\Requests\Attendance\TeachingJournalStoreRequest; use App\Models\TeachingAssignment; use App\Models\TeachingJournal; use App\Services\Attendance\TeachingJournalService; use Illuminate\Http\RedirectResponse; use Illuminate\View\View;
class TeachingJournalController extends Controller{public function index():View{$q=TeachingJournal::with('employee','classroom','subject')->when(!auth()->user()->can('teaching-journals.view'),fn($q)=>$q->where('employee_id',auth()->user()->employee?->id));return view('attendance.journals.index',['journals'=>$q->latest()->paginate(15)]);} public function create():View{return view('attendance.journals.form',['assignments'=>TeachingAssignment::with('classroom','subject')->where('is_active',true)->get()]);} public function store(TeachingJournalStoreRequest $r,TeachingJournalService $s):RedirectResponse{$v=$r->validated();$j=$s->save(TeachingAssignment::findOrFail($v['teaching_assignment_id']),$v,$v['students']??[]);if($v['status']==='submitted')$s->submit($j);return redirect()->route('teaching-journals.show',$j)->with('status','Jurnal tersimpan.');} public function show(TeachingJournal $teachingJournal):View{return view('attendance.journals.show',['journal'=>$teachingJournal->load('employee','classroom','subject','students')]);} public function submit(TeachingJournal $teachingJournal,TeachingJournalService $s):RedirectResponse{$s->submit($teachingJournal);return back()->with('status','Jurnal dikirim.');} public function verify(TeachingJournal $teachingJournal,TeachingJournalService $s):RedirectResponse{$s->verify($teachingJournal);return back()->with('status','Jurnal diverifikasi.');} public function reject(TeachingJournal $teachingJournal,TeachingJournalService $s):RedirectResponse{request()->validate(['rejection_reason'=>['required','string']]);$s->reject($teachingJournal,request('rejection_reason'));return back()->with('status','Jurnal dikembalikan.');}}
